#!/usr/bin/env python3
import base64, os, subprocess

b64_gtm = ""
os.makedirs(os.path.dirname("/var/www/konverta/src/gtm-export.js"), exist_ok=True)
open("/var/www/konverta/src/gtm-export.js", "wb").write(base64.b64decode(b64_gtm))
print("✓ /var/www/konverta/src/gtm-export.js")

print("\n✅ Duplicata removida!")
subprocess.run(["pm2", "restart", "konverta"])